#include<bits/stdc++.h>
using namespace std;
int dis[1000010],f[1000010];
vector<int> mp[1000010];
bool vis[1000010];
void dijkstra()
{
    priority_queue<pair<int,int>> q;
    q.push(make_pair(0,1));
    memset(dis,0x3f,sizeof(dis));
    memset(f,0,sizeof(f));
    memset(vis,0,sizeof(vis));
    f[1]=1;
    dis[1]=0;
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=1;
        for(int i:mp[t])
        {
            if(dis[i]>dis[t]+1)
            {
                dis[i]=dis[t]+1;
                f[i]=f[t];
                q.push(make_pair(-dis[i],i));
            }
            else if(dis[i]==dis[t]+1)
            {
                f[i]+=f[t];
                f[i]%=100003;
            }
        }
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dijkstra();
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",f[i]);
    }
    return 0;
}
